import gradio as grdef recognize_digit(img): # ... implement digit recognition model on input array # ... return dictionary of labels and confidences gr.Interface(fn=recognize_digit, inputs=&#34;sketchpad&#34;, outputs=&#34;label&#34;).launch()
  The single line of code above produces the web interface below. Draw a number 0 through 9 on the sketchpad below and see predictions in real time!
  import gradio as grdef answer_question(paragraph, question): # ... implement Q&amp;A model # ... return answer to questiongr.Interface(fn=answer_question, inputs=[&#34;textbox&#34;, &#34;text&#34;], outputs=&#34;text&#34;).launch()
  Provide a context paragraph and ask a question that can be answered with the context information. Go ahead, type in some information and a question. Then, click submit to get the answer!
  import gradio as grdef face_segmentation(img): # ... implement face segmentation model on input 200x200 numpy array # ... return segmentation mask as numpy arraywebcam = gr.in.Webcam(shape=(200, 200))gr.Interface(fn=face_segmentation, inputs=webcam, outputs=&#34;image&#34;).launch()
  import gradio as gr, matplotlib.pyplot as pltdef outbreak_forecast(r, month, countries, social_distancing): # ... run model to forecast outbreak and generate plots # ... return pltr = gr.in.Slider(1, 5)month = gr.in.Dropdown([&#34;May&#34;, &#34;June&#34;, &#34;July&#34;])countries = gr.in.CheckboxGroup([&#34;USA&#34;, &#34;Canada&#34;, &#34;Mexico&#34;, &#34;UK&#34;])gr.Interface(fn=outbreak_forecast, inputs=[r, month, countries, &#34;checkbox&#34;], outputs=&#34;plot&#34;).launch()
